import{_ as a,a as o}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as r,o as i,c,a2 as t}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Configuración y acceso por WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"es/Safety/webdav-site-access.md","filePath":"es/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),d={name:"es/Safety/webdav-site-access.md"};function n(s,e,l,u,p,b){return i(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="configuracion-y-acceso-por-webdav" tabindex="-1">Configuración y acceso por WebDAV <a class="header-anchor" href="#configuracion-y-acceso-por-webdav" aria-label="Permalink to &quot;Configuración y acceso por WebDAV&quot;">​</a></h1><p>ImgBed puede exponer acceso por WebDAV para revisar archivos desde un explorador de archivos o un cliente compatible.</p><h2 id="cuando-usarlo" tabindex="-1">Cuándo usarlo <a class="header-anchor" href="#cuando-usarlo" aria-label="Permalink to &quot;Cuándo usarlo&quot;">​</a></h2><ul><li>Quieres ver archivos desde Windows o macOS.</li><li>Usas un cliente WebDAV para organizar archivos.</li><li>Necesitas acceder a los archivos fuera del panel de administración.</li></ul><h2 id="conectar-desde-windows-11" tabindex="-1">Conectar desde Windows 11 <a class="header-anchor" href="#conectar-desde-windows-11" aria-label="Permalink to &quot;Conectar desde Windows 11&quot;">​</a></h2><ol><li>Abre el Explorador de archivos.</li><li>Haz clic derecho en <code>Este equipo</code>.</li><li>Elige <code>Agregar una ubicación de red</code>.</li><li>Introduce la URL WebDAV.</li><li>Escribe usuario y contraseña.</li><li>Comprueba que el contenido se abra como una carpeta.</li></ol><p><img src="'+a+'" alt="Configuración WebDAV en Windows 11" loading="lazy"></p><p>Si la conexión es correcta, podrás ver el contenido desde el Explorador.</p><p><img src="'+o+'" alt="WebDAV en Windows" loading="lazy"></p><h2 id="credenciales" tabindex="-1">Credenciales <a class="header-anchor" href="#credenciales" aria-label="Permalink to &quot;Credenciales&quot;">​</a></h2><p>Usa las credenciales configuradas para WebDAV en ImgBed. Para mayor seguridad, conviene usar una cuenta con permisos limitados en lugar de una cuenta principal compartida.</p><h2 id="si-no-conecta" tabindex="-1">Si no conecta <a class="header-anchor" href="#si-no-conecta" aria-label="Permalink to &quot;Si no conecta&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Punto a revisar</th><th>Qué comprobar</th></tr></thead><tbody><tr><td>URL</td><td>Que incluya <code>https://</code> y sea la dirección WebDAV correcta</td></tr><tr><td>Credenciales</td><td>Usuario y contraseña correctos</td></tr><tr><td>Permisos</td><td>Lectura y escritura en el directorio objetivo</td></tr><tr><td>Cliente</td><td>Que Windows o el cliente WebDAV no esté bloqueando la conexión</td></tr></tbody></table><p>Si falla la consulta de capacidad pero la subida funciona, puede ser que el servidor WebDAV no devuelva información de cuota. No siempre significa que el canal no sirva.</p>',14)])])}const _=r(d,[["render",n]]);export{f as __pageData,_ as default};
